import{_ as d,o as r,c as a,a2 as e}from"./chunks/framework.DnrXFDHb.js";const P=JSON.parse('{"title":"智能电网 · 虚拟电厂 · 碳市场","description":"","frontmatter":{},"headers":[],"relativePath":"电力新能源/智能电网/新兴赛道.md","filePath":"电力新能源/智能电网/新兴赛道.md","lastUpdated":1781978464000}'),o={name:"电力新能源/智能电网/新兴赛道.md"};function h(n,t,s,l,i,b){return r(),a("div",null,[...t[0]||(t[0]=[e(`<h1 id="智能电网-·-虚拟电厂-·-碳市场" tabindex="-1">智能电网 · 虚拟电厂 · 碳市场 <a class="header-anchor" href="#智能电网-·-虚拟电厂-·-碳市场" aria-label="Permalink to &quot;智能电网 · 虚拟电厂 · 碳市场&quot;">​</a></h1><p><strong>成熟度：</strong> 智能电网成长期、VPP 爆发初期、碳市场启动期 <strong>PE/VC 重心：</strong> VPP 聚合平台、电力交易 AI、碳管理 SaaS、电力数字化 <strong>数据来源：</strong> China Energy MCP（国家能源局、各省电力交易中心） <strong>数据获取：</strong> 2026-06-15</p><hr><h2 id="电力市场化改革进展-2026年实时数据" tabindex="-1">电力市场化改革进展（2026年实时数据） <a class="header-anchor" href="#电力市场化改革进展-2026年实时数据" aria-label="Permalink to &quot;电力市场化改革进展（2026年实时数据）&quot;">​</a></h2><h3 id="全国现货市场建设情况" tabindex="-1">全国现货市场建设情况 <a class="header-anchor" href="#全国现货市场建设情况" aria-label="Permalink to &quot;全国现货市场建设情况&quot;">​</a></h3><table tabindex="0"><thead><tr><th>状态</th><th>省份</th><th>说明</th></tr></thead><tbody><tr><td>✅ <strong>正式运行</strong></td><td>山西、广东、山东、甘肃、蒙西、湖北、浙江</td><td>7省已正式运行</td></tr><tr><td>🔄 连续结算试运行</td><td>安徽、陕西、辽宁、河北南网、南方区域</td><td>接近转正</td></tr><tr><td>🔄 长周期结算试运行</td><td>福建、四川、江苏、湖南、河南、宁夏、重庆、上海、吉林</td><td>积累运行经验</td></tr><tr><td>🟡 短周期结算试运行</td><td>江西、黑龙江、新疆、蒙东、青海</td><td>探索阶段</td></tr></tbody></table><p><strong>2026年目标：</strong> 全国一半以上省份现货正式运行</p><h3 id="现货电价分化-2026年4月均价" tabindex="-1">现货电价分化（2026年4月均价） <a class="header-anchor" href="#现货电价分化-2026年4月均价" aria-label="Permalink to &quot;现货电价分化（2026年4月均价）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>省份</th><th>均价(元/MWh)</th><th>特点</th><th>VPP/储能套利空间</th></tr></thead><tbody><tr><td>广东</td><td>638</td><td>负荷中心高价</td><td>⭐⭐⭐⭐⭐</td></tr><tr><td>山东</td><td>280</td><td>回落趋势</td><td>⭐⭐⭐</td></tr><tr><td>山西</td><td>230</td><td>时段性供需错配</td><td>⭐⭐⭐</td></tr><tr><td>甘肃</td><td>145</td><td>新能源大发，午间地板价</td><td>⭐⭐⭐⭐（价差大）</td></tr><tr><td>辽宁</td><td>127</td><td>大幅回落</td><td>⭐⭐⭐（基数低）</td></tr></tbody></table><blockquote><p>💡 <strong>对PE/VC的启示：</strong> 各省电价分化是电力交易AI和VPP聚合平台的核心商业逻辑。广东高电价+甘肃低电价→跨省交易套利空间显著。现货市场越成熟的省份，储能/VPP经济性越好。</p></blockquote><blockquote><p>🔗 数据来源：<code>china-energy_get_spot_market</code>, <code>china-energy_get_spot_prices</code></p></blockquote><hr><h2 id="二、智能电网" tabindex="-1">二、智能电网 <a class="header-anchor" href="#二、智能电网" aria-label="Permalink to &quot;二、智能电网&quot;">​</a></h2><h3 id="_1-1-投资主题概览" tabindex="-1">1.1 投资主题概览 <a class="header-anchor" href="#_1-1-投资主题概览" aria-label="Permalink to &quot;1.1 投资主题概览&quot;">​</a></h3><table tabindex="0"><thead><tr><th>子赛道</th><th>核心驱动</th><th>市场空间</th><th>一级热度</th></tr></thead><tbody><tr><td>配电自动化</td><td>配网投资加码（十五五配网投资超电网50%）</td><td>千亿级</td><td>⭐⭐⭐</td></tr><tr><td>电力物联网</td><td>新型电力系统信息化需求</td><td>百亿级</td><td>⭐⭐⭐</td></tr><tr><td>智能电表 AMI</td><td>新一代电表替换+IR46标准</td><td>200亿+/年</td><td>⭐⭐</td></tr><tr><td>电力信息化</td><td>营销/调度/交易系统升级</td><td>百亿级</td><td>⭐⭐⭐</td></tr><tr><td>微电网</td><td>工业园区/海岛/偏远地区</td><td>数十亿</td><td>⭐⭐⭐⭐</td></tr></tbody></table><h3 id="_1-2-pe-vc-机会" tabindex="-1">1.2 PE/VC 机会 <a class="header-anchor" href="#_1-2-pe-vc-机会" aria-label="Permalink to &quot;1.2 PE/VC 机会&quot;">​</a></h3><ul><li><strong>配电侧数字化</strong> — 配网自动化覆盖率当前~30%，十五五目标60%+</li><li><strong>电力AI调度</strong> — 新能源出力预测、潮流优化、故障自愈</li><li><strong>微电网解决方案</strong> — 光储充独立微网系统集成商</li><li><strong>电力网络安全</strong> — 电网侧工控安全（等保2.0+电力行业要求）</li></ul><p><strong>代表公司：</strong></p><ul><li>国电南瑞/许继电气（上市龙头，一级机会有限）</li><li>数字配电初创：映翰通/智光电气/力控科技</li><li>电力AI调度：清大科越（Pre-IPO）、瓦特智能（A轮）</li></ul><hr><h2 id="三、虚拟电厂-vpp" tabindex="-1">三、虚拟电厂 (VPP) <a class="header-anchor" href="#三、虚拟电厂-vpp" aria-label="Permalink to &quot;三、虚拟电厂 (VPP)&quot;">​</a></h2><h3 id="_3-1-市场规模" tabindex="-1">3.1 市场规模 <a class="header-anchor" href="#_3-1-市场规模" aria-label="Permalink to &quot;3.1 市场规模&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指标</th><th>2024</th><th>2026E</th><th>2028E</th></tr></thead><tbody><tr><td>中国VPP可调容量</td><td>~10GW</td><td>~50GW</td><td>~150GW</td></tr><tr><td>中国VPP市场规模</td><td>~50亿</td><td>~300亿</td><td>~1000亿</td></tr><tr><td>聚合用户数</td><td>~100万</td><td>~500万</td><td>~2000万</td></tr></tbody></table><p><strong>核心驱动力：</strong> 电力现货市场提速 + 分布式资源爆发 + 政策强制需求侧响应</p><h3 id="_3-2-商业模式" tabindex="-1">3.2 商业模式 <a class="header-anchor" href="#_3-2-商业模式" aria-label="Permalink to &quot;3.2 商业模式&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模式</th><th>收益来源</th><th>利润率</th><th>壁垒</th></tr></thead><tbody><tr><td>聚合运营（轻资产）</td><td>电能量交易+辅助服务分成</td><td>中</td><td>算法+渠道</td></tr><tr><td>资产投资（重资产）</td><td>储能/光伏资产投资收益</td><td>中低</td><td>资金+运维</td></tr><tr><td>SaaS 平台</td><td>软件订阅+交易撮合</td><td>高</td><td>平台效应</td></tr><tr><td>虚拟电厂整体方案</td><td>EPC+运营+设备</td><td>中</td><td>系统集成能力</td></tr></tbody></table><h3 id="_3-3-pe-vc-标的" tabindex="-1">3.3 PE/VC 标的 <a class="header-anchor" href="#_3-3-pe-vc-标的" aria-label="Permalink to &quot;3.3 PE/VC 标的&quot;">​</a></h3><table tabindex="0"><thead><tr><th>公司</th><th>方向</th><th>阶段</th><th>备注</th></tr></thead><tbody><tr><td><strong>浙达能源</strong></td><td>VPP 聚合平台+储能运营</td><td>B轮</td><td>浙江，资源丰富</td></tr><tr><td><strong>零碳智能</strong></td><td>VPP SaaS</td><td>A轮</td><td>平台模式</td></tr><tr><td><strong>电享科技</strong></td><td>VPP+充电桩聚合</td><td>B轮</td><td>蔚来资本投资</td></tr><tr><td><strong>清大科越</strong></td><td>电力交易+调度</td><td>Pre-IPO</td><td>软件+算法</td></tr><tr><td><strong>泰豪软件</strong></td><td>电力市场交易</td><td>上市公司</td><td>—</td></tr><tr><td><strong>海澜智云</strong></td><td>工业能效+VPP</td><td>B轮</td><td>江苏</td></tr><tr><td><strong>长园能源</strong></td><td>微电网+VPP</td><td>A轮</td><td>长园集团</td></tr><tr><td><strong>电管家</strong></td><td>分布式能源聚合</td><td>B轮</td><td>—</td></tr><tr><td><strong>慧联无限</strong></td><td>电力物联网+VPP</td><td>B轮</td><td>—</td></tr><tr><td><strong>兆瓦云</strong></td><td>VPP 运营+交易</td><td>A轮</td><td>华北</td></tr></tbody></table><h3 id="_3-4-关键指标" tabindex="-1">3.4 关键指标 <a class="header-anchor" href="#_3-4-关键指标" aria-label="Permalink to &quot;3.4 关键指标&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>VPP 平台核心竞争力：</span></span>
<span class="line"><span>  1. 聚合资源类型（工商储能+充电桩+分布式光伏+可控负荷）</span></span>
<span class="line"><span>  2. 交易算法精度（日前预测误差&lt;5%）</span></span>
<span class="line"><span>  3. 聚合可调容量（MW级）</span></span>
<span class="line"><span>  4. 响应速度（秒级辅助服务能力）</span></span></code></pre></div><hr><h2 id="四、碳市场" tabindex="-1">四、碳市场 <a class="header-anchor" href="#四、碳市场" aria-label="Permalink to &quot;四、碳市场&quot;">​</a></h2><h3 id="_4-1-中国碳市场现状" tabindex="-1">4.1 中国碳市场现状 <a class="header-anchor" href="#_4-1-中国碳市场现状" aria-label="Permalink to &quot;4.1 中国碳市场现状&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指标</th><th>数值</th><th>说明</th></tr></thead><tbody><tr><td>行业覆盖</td><td>电力行业（首批）</td><td>2026年扩围至钢铁/水泥/电解铝</td></tr><tr><td>控排企业</td><td>~2200家（首批）</td><td>扩围后 ~8000家</td></tr><tr><td>碳价</td><td>70-100元/吨（2025-2026）</td><td>欧盟~60-80欧元/吨</td></tr><tr><td>年交易量</td><td>~3亿吨</td><td>欧盟~80亿吨</td></tr><tr><td>CCER 重启</td><td>2024年重启</td><td>方法学首批 造林/光热/海上风电</td></tr></tbody></table><h3 id="_4-2-pe-vc-机会" tabindex="-1">4.2 PE/VC 机会 <a class="header-anchor" href="#_4-2-pe-vc-机会" aria-label="Permalink to &quot;4.2 PE/VC 机会&quot;">​</a></h3><p><strong>碳管理 SaaS：</strong> 企业碳核算/碳足迹/ESG 报告（需求确定性高，政策合规驱动）</p><table tabindex="0"><thead><tr><th>公司</th><th>方向</th><th>阶段</th></tr></thead><tbody><tr><td><strong>碳阻迹</strong></td><td>碳管理SaaS+咨询</td><td>B轮</td></tr><tr><td><strong>中创碳投</strong></td><td>碳咨询+数据</td><td>A轮</td></tr><tr><td><strong>绿普惠</strong></td><td>碳普惠C端</td><td>A轮</td></tr><tr><td><strong>妙盈科技</strong></td><td>ESG+碳数据</td><td>C轮</td></tr><tr><td><strong>诺比节能</strong></td><td>工业碳管理</td><td>B轮</td></tr></tbody></table><p><strong>碳监测 CEMS：</strong> 连续排放监测系统（碳市场扩围→强制监测需求爆发）</p><table tabindex="0"><thead><tr><th>公司</th><th>方向</th><th>阶段</th></tr></thead><tbody><tr><td><strong>雪迪龙</strong> (已上市)</td><td>CEMS 设备</td><td>—</td></tr><tr><td><strong>聚光科技</strong> (已上市)</td><td>环境监测</td><td>—</td></tr><tr><td><strong>蓝盾光电</strong></td><td>CEMS</td><td>上市公司</td></tr><tr><td><strong>CEMS 初创</strong></td><td>新型碳监测传感器</td><td>天使-A轮</td></tr></tbody></table><p><strong>碳金融/碳交易：</strong></p><table tabindex="0"><thead><tr><th>业务模式</th><th>说明</th><th>准入壁垒</th></tr></thead><tbody><tr><td>碳资产管理</td><td>为控排企业提供配额交易/履约服务</td><td>资质+经验</td></tr><tr><td>碳回购/质押融资</td><td>碳资产金融化</td><td>金融牌照</td></tr><tr><td>碳指数/数据服务</td><td>碳价预测/碳数据API</td><td>数据积累</td></tr></tbody></table><p><strong>碳资产/CCER：</strong></p><table tabindex="0"><thead><tr><th>方向</th><th>说明</th><th>阶段</th></tr></thead><tbody><tr><td>林业碳汇 CCER</td><td>造林碳汇开发</td><td>早期</td></tr><tr><td>海上风电 CCER</td><td>2024首批方法学</td><td>已有项目</td></tr><tr><td>光热发电 CCER</td><td>2024首批方法学</td><td>—</td></tr><tr><td>VCS 国际</td><td>自愿减排国际标准</td><td>—</td></tr></tbody></table><hr><h2 id="五、ai-能源交叉-重点关注" tabindex="-1">五、AI+能源交叉（重点关注） <a class="header-anchor" href="#五、ai-能源交叉-重点关注" aria-label="Permalink to &quot;五、AI+能源交叉（重点关注）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>方向</th><th>场景</th><th>壁垒</th><th>一级热度</th></tr></thead><tbody><tr><td>AI 功率预测</td><td>风光出力预测、精度提升～5%</td><td>数据+算法</td><td>⭐⭐⭐⭐</td></tr><tr><td>AI 电力交易</td><td>现货市场报价策略</td><td>算法+市场经验</td><td>⭐⭐⭐⭐</td></tr><tr><td>AI 智能运维</td><td>风机/光伏故障预测</td><td>行业知识</td><td>⭐⭐⭐</td></tr><tr><td>AI 虚拟电厂</td><td>聚合调度优化</td><td>平台+数据</td><td>⭐⭐⭐⭐⭐</td></tr><tr><td>AI 碳管理</td><td>碳排放核算自动化</td><td>数据整合</td><td>⭐⭐⭐</td></tr></tbody></table><p><strong>重点关注方向（AI+VPP+电力交易）</strong> — 交叉赛道溢价显著</p><hr><h2 id="四、碳市场-已独立为完整赛道" tabindex="-1">四、碳市场（已独立为完整赛道） <a class="header-anchor" href="#四、碳市场-已独立为完整赛道" aria-label="Permalink to &quot;四、碳市场（已独立为完整赛道）&quot;">​</a></h2><blockquote><p>⚡ 碳市场内容已拆分至独立赛道文件：👉 <a href="./../碳市场/赛道文件">碳市场/赛道文件.md</a></p><p>本文件保留碳市场概览链接，完整内容详见独立赛道文件。</p></blockquote><p>碳市场2026年核心动态：</p><ul><li><strong>行业扩围：</strong> 钢铁、水泥、铝冶炼正式纳入，覆盖排放量从50亿吨→80亿吨</li><li><strong>碳价趋势：</strong> CEA ~80元/吨，CCER ~81元/吨（2026年6月复旦指数）</li><li><strong>后续行业：</strong> 石化、化工、建材、造纸、民航预计2027-2028扩围</li><li><strong>PE/VC机会：</strong> 碳管理SaaS（确定性最高）、碳监测CEMS（政策刚需）、碳金融（牌照壁垒）</li></ul><hr><h2 id="六、交叉链接" tabindex="-1">六、交叉链接 <a class="header-anchor" href="#六、交叉链接" aria-label="Permalink to &quot;六、交叉链接&quot;">​</a></h2><table tabindex="0"><thead><tr><th>关联赛道</th><th>链接</th><th>说明</th></tr></thead><tbody><tr><td><strong>算电协同</strong></td><td><a href="./../算电协同/赛道总览">赛道总览</a></td><td>VPP 聚合数据中心是算电协同核心落地场景</td></tr><tr><td><strong>算电协同</strong></td><td><a href="./../算电协同/投资逻辑">投资逻辑</a></td><td>VPP 聚合平台是优先布局方向之一</td></tr><tr><td><strong>储能</strong></td><td><a href="./../储能/产业链">产业链</a></td><td>储能是 VPP 最大可调资源</td></tr><tr><td><strong>AI 应用层</strong></td><td><a href="./../../AI/应用层/AI应用赛道#17-ai能源重点交叉">AI+能源</a></td><td>AI+电力交易、AI+VPP</td></tr><tr><td><strong>碳市场</strong></td><td><a href="./../碳市场/赛道文件">赛道文件</a></td><td>碳管理 SaaS + VPP 碳收益</td></tr><tr><td><strong>电力市场（电改2.0）</strong></td><td><a href="./../电力市场/赛道文件">赛道文件</a></td><td>现货市场/VPP 纳入国家框架</td></tr></tbody></table>`,55)])])}const p=d(o,[["render",h]]);export{P as __pageData,p as default};
